mapper.update:
UPDATE ai_capability_access_token
SET last_used_at = #{lastUsedAt}, update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND id = #{id}
  AND status = 'ACTIVE'
  AND expires_at > #{lastUsedAt}
  AND del_flag = 0

UPDATE ai_capability_access_token
SET status = 'REVOKED', revoked_at = #{revokedAt}, update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND id = #{id}
  AND status = 'ACTIVE'
  AND del_flag = 0

UPDATE ai_capability_access_token
SET status = 'REVOKED', revoked_at = #{revokedAt}, update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND client_id = #{clientId}
  AND credential_version = #{credentialVersion}
  AND status = 'ACTIVE'
  AND del_flag = 0

mapper.delete:
DELETE FROM ai_capability_access_token
WHERE (expires_at < #{retentionCutoff}
    OR (status = 'REVOKED' AND revoked_at < #{retentionCutoff}))
